def normalize_and_parse(raw_value):
    # 1. Loại bỏ khoảng trắng thừa ở đầu và cuối chuỗi
    cleaned = raw_value.strip()

    # 2. Xử lý các giá trị đặc biệt dạng chuỗi logic
    if cleaned.lower() == 'true':
        return True
    if cleaned.lower() == 'false':
        return False

    # 3. Phân tích ngữ cảnh để ép kiểu tối ưu (float hoặc int)
    try:
        if '.' in cleaned:
            return float(cleaned)
        return int(cleaned)
    except ValueError:
        # Giữ nguyên kiểu chuỗi đã làm sạch nếu không thể chuyển thành số
        return cleaned

