    digits = [char for char in data_str if char.isdigit()]
    formatted_chunks = []
    # Sử dụng range với bước nhảy để nhóm các chữ số thành từng cặp
    for i in range(0, len(digits), 2):
        chunk = ''.join(digits[i:i+2])
        formatted_chunks.append(chunk)
    return '-'.join(formatted_chunks)

