    # Sử dụng break để thoát sớm ngay khi tìm thấy giá trị đạt yêu cầu nhằm tối ưu hóa thuật toán
    first_prime = None
    for num in numbers:
        if num < 2:
            continue
        is_prime = True
        for i in range(2, int(num ** 0.5) + 1):
            if num % i == 0:
                is_prime = False
                break  # Thoát vòng lặp kiểm tra ước số
        if is_prime:
            first_prime = num
            break  # Tìm thấy số nguyên tố đầu tiên, thoát vòng lặp chính ngay lập tức
    return first_prime

