import sys

def ve_hinh_thoi_rong_tinh_toan_manhattan(n):
    # Vẽ hình thoi rỗng bằng công thức khoảng cách tuyệt đối hình học phẳng (Manhattan distance)
    # n nên là số lẻ để hình thoi cân đối tuyệt đối
    if n % 2 == 0:
        n += 1
    mid = n // 2
    print(f"\nHình thoi rỗng kích thước {n}x{n} (Tâm tại {mid},{mid}):")
    for r in range(n):
        for c in range(n):
            if abs(r - mid) + abs(c - mid) == mid:
                print("*", end=" ")
            else:
                print(" ", end=" ")
        print()

def ve_ban_co_vua_toi_uu_hieu_nang(size):
    # Tối ưu hóa I/O bằng cách gom hệ thống đệm chuỗi tránh nghẽn I/O hệ thống
    # Tránh gọi print() quá nhiều lần trong vòng lặp lồng sâu
    print(f"\nBàn cờ vua ({size}x{size}) - Phiên bản tối ưu I/O:")
    buffer = []
    for r in range(size):
        row_data = []
        for c in range(size):
            # Đan xen ô sáng tối
            if (r + c) % 2 == 0:
                row_data.append("██")
            else:
                row_data.append("  ")
        buffer.append("".join(row_data))

    # Ghi toàn bộ dữ liệu ra màn hình chỉ bằng một lệnh I/O duy nhất
    sys.stdout.write("\n".join(buffer) + "\n")

